// S3 + Phase 4: Single router, agent mode selection by domain
const wh = $('Webhook').first().json;
const input = wh.body || wh;

const TIER_MODELS = {
  0: 'gemini-2.0-flash',
  1: 'gemini-2.0-flash-lite',
  2: 'groq/llama-3.3-70b',
  3: 'ollama/llama3.1',
};

const AGENT_MAP = { JOB: 'jeff', PERSONAL: 'eilinaire', CREATIVE: 'ego_era' };

// Phase 4: Agent mode by domain
const DOMAIN_AGENT = {
  'marketing': 'marketing',
  'writing':   'writing',
  'trading':   'trading',
};

const SYSTEM_PROMPTS = {
  'marketing': 'You are Jeff, COPREM Marketing Strategist. Analyze marketing opportunities, suggest campaigns, and provide data-driven insights. Reply in Thai when user writes Thai. ALWAYS propose your plan first and wait for approval before any external action.',
  'writing':   'You are Jeff, COPREM Writing Partner. Help craft compelling content, refine prose, and maintain brand voice. Reply in Thai when user writes Thai. ALWAYS propose your draft first and wait for approval before publishing.',
  'trading':   'You are Jeff, COPREM Market Analyst (READ-ONLY). Provide market analysis, identify opportunities, and explain risks. NEVER execute trades or provide specific trade instructions. Analyst mode only. Reply in Thai when user writes Thai.',
  'default':   'You are Jeff, Prems INTJ AI Executive Partner. Be direct, analytical. Reply in Thai when user writes Thai.',
};

const pillar = ((input.pillar || 'JOB').split('.')[0]).toUpperCase();
const domain = (input.domain || '').toLowerCase();
const throttled = {};

for (const row of $('Check Rate Limits').all()) {
  if (row.json.is_throttled) throttled[row.json.provider] = true;
}

let tier = 0;
if (throttled['gemini-2.0-flash'] && throttled['gemini-2.0-flash-lite']) tier = 3;
else if (throttled['gemini-2.0-flash'] && throttled['groq/llama-3.3-70b']) tier = 3;
else if (throttled['gemini-2.0-flash']) tier = 2;

let selectedModel = TIER_MODELS[tier];
if (throttled[selectedModel]) selectedModel = 'ollama/llama3.1';

const agent_mode = DOMAIN_AGENT[domain] || null;
const system_prompt = SYSTEM_PROMPTS[agent_mode] || SYSTEM_PROMPTS['default'];

return [{ json: {
  assigned_agent: AGENT_MAP[pillar] || 'jeff',
  selected_model: selectedModel,
  agent_mode,
  system_prompt,
  tier,
  pillar,
  domain,
  message: input.message || '',
  user_id: input.user_id || '',
  context: input.context || '',
  routed_at: new Date().toISOString()
}}];

